"""
MKT Christ Commentary — Matthew chapters 5–6 (and whole-book key verses)
Run: python3 scripts/zc-christ-matthew-5-6.py

Source data used:
- data/interlinear/matthew.json
- data/translation/draft/mediating/matthew.json (MKT text)
- data/echoes/matthew.json (OT echo layer, chapters 5–6)
- data/commentary/ellicott/matthew.json (philological support)

Key decisions in this range:
- The Sermon on the Mount is read with the New Moses typology established at 5:1 (echoed
  from Exod 19:3); Jesus on the mountain mirrors Moses on Sinai, but speaks on his own
  authority ("But I say to you") rather than as a transmitter.
- The beatitudes are classified as "fulfillment": Luke 4:18–19 explicitly cites Isa 61 as
  fulfilled in Christ, so Matthew's Beatitudes — drawing on the same Isaianic anawim
  tradition — are treated as the Messiah distributing what he embodies.
- The "You have heard... but I say to you" antitheses are classified as "revelation of God":
  Jesus speaks with the voice that gave the Law at Sinai, not merely interpreting it but
  authoritatively extending it from act to disposition.
- 5:17 ("I came to fulfill") is classified as "direct" — an explicit self-referential claim
  that Christ is the telos of Torah and Prophets (see also Rom 10:4).
- The Lord's Prayer (6:9–13) is classified as "revelation of God": Christ teaches his
  disciples to address God as Father, grounding the prayer in the filial relationship he
  makes available.
- 6:33 ("seek first the kingdom") is "direct": seeking the kingdom means following the one
  who brings and embodies it.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


